#!/usr/bin/env node
/**
 * Build SDK changelog pages from GitHub Releases.
 *
 * Pulls releases for each SDK repo via `gh api`, groups them by major
 * version, and renders an MDX page per SDK under `content/docs/changelog/`.
 *
 * Source of truth for each language SDK:
 *   - Python:     runvendo/vendo-sdk-py
 *   - TypeScript: runvendo/vendo-sdk-js
 *   - Swift:      runvendo/vendo-sdk-swift
 *
 * If a repo has no GitHub Releases (only git tags), falls back to
 * `gh api repos/{owner}/{repo}/tags` and renders a tag-only changelog
 * with a one-line note.
 *
 * Generated files carry a header comment and must not be hand-edited.
 *
 * TODO(automation): run this on a GitHub Action cron (daily) and open a PR
 *   with refreshed output. Not implemented in this PR.
 *
 * Usage: node scripts/build-changelog.mjs
 */

import { spawnSync } from "node:child_process";
import { writeFileSync, mkdirSync } from "node:fs";
import { dirname, join, resolve } from "node:path";
import { fileURLToPath } from "node:url";

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);
const REPO_ROOT = resolve(__dirname, "..");
const OUT_DIR = join(REPO_ROOT, "content", "docs", "changelog");

const SDKS = [
  {
    slug: "sdk-python",
    title: "Python SDK",
    description: "Release history for vendo-sdk-py.",
    language: "Python",
    repo: "runvendo/vendo-sdk-py",
    installHint: "pip install vendo-sdk",
  },
  {
    slug: "sdk-typescript",
    title: "TypeScript SDK",
    description: "Release history for vendo-sdk-js.",
    language: "TypeScript",
    repo: "runvendo/vendo-sdk-js",
    installHint: "npm install @vendodev/sdk",
  },
  {
    slug: "sdk-swift",
    title: "Swift SDK",
    description: "Release history for vendo-sdk-swift.",
    language: "Swift",
    repo: "runvendo/vendo-sdk-swift",
    installHint: "Swift Package Manager",
  },
];

const HEADER = "{/* Generated by scripts/build-changelog.mjs. Do not edit by hand. */}";

function gh(args) {
  const result = spawnSync("gh", args, { encoding: "utf8" });
  if (result.status !== 0) {
    throw new Error(
      `gh ${args.join(" ")} failed (status ${result.status}): ${result.stderr.trim()}`,
    );
  }
  return result.stdout;
}

function fetchReleases(repo) {
  const raw = gh([
    "api",
    "--paginate",
    `repos/${repo}/releases?per_page=100`,
  ]);
  const releases = JSON.parse(`[${raw.trim().replace(/\]\s*\[/g, ",")}]`);
  return releases.flat().map((r) => ({
    tag: r.tag_name,
    name: r.name || r.tag_name,
    date: r.published_at || r.created_at,
    prerelease: Boolean(r.prerelease),
    draft: Boolean(r.draft),
    url: r.html_url,
    body: (r.body || "").trim(),
  }));
}

function fetchTags(repo) {
  const raw = gh([
    "api",
    "--paginate",
    `repos/${repo}/tags?per_page=100`,
  ]);
  const tags = JSON.parse(`[${raw.trim().replace(/\]\s*\[/g, ",")}]`);
  return tags.flat().map((t) => ({
    tag: t.name,
    name: t.name,
    url: `https://github.com/${repo}/releases/tag/${encodeURIComponent(t.name)}`,
    commit: t.commit?.sha,
  }));
}

function majorOf(tag) {
  const m = String(tag).match(/v?(\d+)/);
  return m ? Number(m[1]) : 0;
}

function compareTag(a, b) {
  const parse = (t) =>
    String(t)
      .replace(/^v/, "")
      .split(/[.+-]/)
      .map((p) => (/^\d+$/.test(p) ? Number(p) : p));
  const ap = parse(a);
  const bp = parse(b);
  for (let i = 0; i < Math.max(ap.length, bp.length); i++) {
    const av = ap[i] ?? 0;
    const bv = bp[i] ?? 0;
    if (av === bv) continue;
    if (typeof av === "number" && typeof bv === "number") return bv - av;
    return String(bv).localeCompare(String(av));
  }
  return 0;
}

function escapeMdx(text) {
  // Body is rendered as MDX. Most GitHub release bodies are plain markdown,
  // which renders cleanly. Guard against stray HTML-style angle brackets that
  // MDX would parse as components.
  return text.replace(/<(?=[^a-zA-Z/!])/g, "&lt;");
}

function formatDate(iso) {
  if (!iso) return "";
  const d = new Date(iso);
  if (Number.isNaN(d.getTime())) return "";
  return d.toISOString().slice(0, 10);
}

function renderReleasePage(sdk, releases) {
  const sorted = [...releases].sort((a, b) => compareTag(a.tag, b.tag));
  const groups = new Map();
  for (const r of sorted) {
    const k = majorOf(r.tag);
    if (!groups.has(k)) groups.set(k, []);
    groups.get(k).push(r);
  }
  const majors = [...groups.keys()].sort((a, b) => b - a);

  const lines = [];
  lines.push("---");
  lines.push(`title: ${sdk.title}`);
  lines.push(`description: ${sdk.description}`);
  lines.push("---");
  lines.push("");
  lines.push(HEADER);
  lines.push("");
  lines.push(
    `Release history for [\`${sdk.repo}\`](https://github.com/${sdk.repo}). Install: \`${sdk.installHint}\`.`,
  );
  lines.push("");
  lines.push(
    `Generated from GitHub Releases on ${formatDate(new Date().toISOString())}. To pull the latest, run \`npm run changelog\`.`,
  );
  lines.push("");

  for (const major of majors) {
    lines.push(`## v${major}.x`);
    lines.push("");
    for (const r of groups.get(major)) {
      const tagLabel = r.tag.startsWith("v") ? r.tag : `v${r.tag}`;
      const flags = [];
      if (r.prerelease) flags.push("pre-release");
      if (r.draft) flags.push("draft");
      const flagSuffix = flags.length ? ` _(${flags.join(", ")})_` : "";
      const date = formatDate(r.date);
      lines.push(
        `### [${tagLabel}](${r.url})${date ? ` — ${date}` : ""}${flagSuffix}`,
      );
      lines.push("");
      if (r.body) {
        lines.push(escapeMdx(r.body));
        lines.push("");
      } else {
        lines.push("_No release notes._");
        lines.push("");
      }
    }
  }

  return lines.join("\n");
}

function renderTagOnlyPage(sdk, tags) {
  const sorted = [...tags].sort((a, b) => compareTag(a.tag, b.tag));
  const lines = [];
  lines.push("---");
  lines.push(`title: ${sdk.title}`);
  lines.push(`description: ${sdk.description}`);
  lines.push("---");
  lines.push("");
  lines.push(HEADER);
  lines.push("");
  lines.push(
    `Release history for [\`${sdk.repo}\`](https://github.com/${sdk.repo}). Install: \`${sdk.installHint}\`.`,
  );
  lines.push("");
  lines.push(
    "_No GitHub Releases published for this repo yet — listing git tags only. Full release notes will appear here once Releases are cut._",
  );
  lines.push("");
  lines.push("## Tags");
  lines.push("");
  for (const t of sorted) {
    const tagLabel = t.tag.startsWith("v") ? t.tag : `v${t.tag}`;
    lines.push(`- [${tagLabel}](${t.url})`);
  }
  lines.push("");
  return lines.join("\n");
}

function renderEmptyPage(sdk) {
  const lines = [];
  lines.push("---");
  lines.push(`title: ${sdk.title}`);
  lines.push(`description: ${sdk.description}`);
  lines.push("---");
  lines.push("");
  lines.push(HEADER);
  lines.push("");
  lines.push(
    `No releases or tags published yet for [\`${sdk.repo}\`](https://github.com/${sdk.repo}). This page populates automatically once the first release ships.`,
  );
  lines.push("");
  return lines.join("\n");
}

function build() {
  mkdirSync(OUT_DIR, { recursive: true });
  const counts = [];
  for (const sdk of SDKS) {
    let releases = [];
    try {
      releases = fetchReleases(sdk.repo);
    } catch (err) {
      console.warn(`! ${sdk.repo}: releases fetch failed: ${err.message}`);
    }
    let content;
    let mode;
    if (releases.length > 0) {
      content = renderReleasePage(sdk, releases);
      mode = "releases";
      counts.push(`${sdk.language}: ${releases.length}`);
    } else {
      let tags = [];
      try {
        tags = fetchTags(sdk.repo);
      } catch (err) {
        console.warn(`! ${sdk.repo}: tags fetch failed: ${err.message}`);
      }
      if (tags.length > 0) {
        content = renderTagOnlyPage(sdk, tags);
        mode = "tags-only";
        counts.push(`${sdk.language}: ${tags.length} (tags)`);
      } else {
        content = renderEmptyPage(sdk);
        mode = "empty";
        counts.push(`${sdk.language}: 0`);
      }
    }
    const outPath = join(OUT_DIR, `${sdk.slug}.mdx`);
    writeFileSync(outPath, content);
    console.log(`  wrote ${outPath} (${mode})`);
  }
  console.log("");
  console.log(`Releases rendered — ${counts.join(", ")}`);
}

build();
